INSERT INTO `questions` (`id`, `topic_id`, `question_type`, `locale`, `real_life_context`, `question_text`, `correct_answer`, `correct_answer_numeric`, `hint_text`, `explanation`, `image_url`, `created_at`, `updated_at`) VALUES
(1, 1, 'mcq', 'ar', 'أحمد راح الكانتين المدرسة واشترى ساندوتش وعصير', 'أحمد اشترى ساندوتش بـ 15 جنيه وعصير بـ 8 جنيه. كم دفع؟', NULL, NULL, 'اجمع تمن الساندوتش مع تمن العصير', '15 + 8 = 23 جنيه', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(2, 1, 'mcq', 'ar', 'سارة معاها مصروف 50 جنيه واشترت أدوات مدرسية', 'سارة معاها 50 جنيه واشترت كراسة بـ 12 جنيه وقلم بـ 8 جنيه. المتبقي معاها كام؟', NULL, NULL, 'اجمع اللي اشترته الأول وبعدين اطرح من الـ 50', '12 + 8 = 20 جنيه مشتريات. 50 - 20 = 30 جنيه المتبقية', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(3, 1, 'mcq', 'ar', 'كريم يجمع مال الحصّالة بتاعته', 'كريم عنده 125 جنيه في الحصّالة وأضاف 75 جنيه. المجموع كام؟', NULL, NULL, 'اجمع الرقمين مع بعض', '125 + 75 = 200 جنيه', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(4, 1, 'mcq', 'ar', 'نور راحت السوبر ماركت مع ماما وبيحسبوا الفاتورة', 'الفاتورة كانت 237 جنيه وماما دفعت 300 جنيه. الباقي كام؟', NULL, NULL, 'اطرح الفاتورة من المبلغ اللي اتدفع', '300 - 237 = 63 جنيه', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(5, 1, 'mcq', 'ar', 'عمر بيشتري هدية لصاحبه من محل لعب', 'عمر اشترى لعبة بـ 45 جنيه وكارت معايدة بـ 15 جنيه وكيس هدايا بـ 5 جنيه. المجموع كام؟', NULL, NULL, 'اجمع الثلاث حاجات مع بعض', '45 + 15 + 5 = 65 جنيه', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(6, 1, 'mcq', 'ar', 'ياسمين بتوفر من مصروفها كل أسبوع', 'ياسمين وفرت 148 جنيه هذا الشهر وصرفت 59 جنيه على كتاب. كم يتبقى؟', NULL, NULL, 'اطرح ثمن الكتاب من اللي وفرته', '148 - 59 = 89 جنيه', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(7, 1, 'mcq', 'ar', 'محل الكانتين بيعمل حساب آخر اليوم', 'الكانتين باع الصبح بـ 350 جنيه وبعد الضهر بـ 275 جنيه. مجموع المبيعات كام؟', NULL, NULL, 'اجمع مبيعات الصبح مع بعد الضهر', '350 + 275 = 625 جنيه', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(8, 1, 'mcq', 'ar', 'مريم بتشتري لبس المدرسة الجديد', 'مريم اشترت بلوزة بـ 120 جنيه وجيبة بـ 95 جنيه. لو معاها 250 جنيه، هيتبقى كام؟', NULL, NULL, 'اجمع تمن الحاجتين وبعدين اطرح من 250', '120 + 95 = 215 جنيه. 250 - 215 = 35 جنيه', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(9, 1, 'open_ended', 'ar', 'خالد اشترى من الكانتين تفاح وموز', 'خالد اشترى تفاح بـ 10 جنيه وموز بـ 7 جنيه. كم دفع في المجموع؟', '17', 17, 'اجمع التمنين مع بعض', '10 + 7 = 17 جنيه', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(10, 1, 'open_ended', 'ar', 'مريم معاها مصروف الأسبوع وتريد تشتري أكل', 'مريم معاها 100 جنيه واشترت أكل بـ 64 جنيه. المتبقي معاها كم جنيه؟', '36', 36, 'اطرح تمن الأكل من اللي معاها', '100 - 64 = 36 جنيه', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(11, 1, 'open_ended', 'ar', 'أحمد يجمع مال حتى يشتري كورة', 'أحمد معاه 86 جنيه ومحتاج 150 جنيه حتى الكورة. يحتاج أن يوفر كم المزيد؟', '64', 64, 'اطرح اللي معاه من تمن الكورة', '150 - 86 = 64 جنيه لسه يحتاج أن يوفرهم', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(12, 1, 'open_ended', 'ar', 'نور بتحسب مشتريات ماما من الخضري', 'ماما اشترت خضار بـ 45 جنيه وفاكهة بـ 38 جنيه ولحمة بـ 120 جنيه. المجموع كام؟', '203', 203, 'اجمع التلات أرقام مع بعض', '45 + 38 = 83، وبعدين 83 + 120 = 203 جنيه', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(13, 2, 'mcq', 'ar', 'سارة بتشتري كراسات لأخواتها الثلاثة', 'كل كراسة بـ 12 جنيه وسارة تريد 3 كراسات. كم ستدفع؟', NULL, NULL, 'اضرب تمن الكراسة في عدد الكراسات', '12 × 3 = 36 جنيه', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(14, 2, 'mcq', 'ar', 'المدرّسة بتجهز أدوات لحصة العلوم', 'المدرّسة محتاجة 5 مجموعات تجارب، كل مجموعة بـ 25 جنيه. التكلفة كام؟', NULL, NULL, 'اضرب 5 في 25', '5 × 25 = 125 جنيه', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(15, 2, 'mcq', 'ar', 'عمر بيشتري عُلب عصير لحفلة الفصل', 'كل علبة عصير بـ 7 جنيه وعمر اشترى 8 علب. الحساب كام؟', NULL, NULL, 'اضرب 7 في 8', '7 × 8 = 56 جنيه', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(16, 2, 'mcq', 'ar', 'مريم بتنظم رحلة الفصل وبتحسب تكلفة التذاكر', 'تذكرة الحديقة بـ 35 جنيه وعدد التلاميذ 4. التكلفة الكلية كام؟', NULL, NULL, 'اضرب تمن التذكرة في عدد التلاميذ', '35 × 4 = 140 جنيه', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
