(29, 3, 'mcq', 'ar', 'نور توزع موز على إخواتها', 'نور عندها 23 موزة وتريد توزعهم على 3 إخوات. كل واحد يأخذ كم ويتبقى كام؟', NULL, NULL, 'اقسم 23 على 3', '23 ÷ 3 = 7 لكل واحد والباقي 2 (لأن 3 × 7 = 21)', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
