(33, 3, 'open_ended', 'ar', 'مريم عندها فواكه وتريد توزعها', 'مريم عندها 36 حلاوة وتريد توزعهم على 6 أصدقاء بالتساوي. كل واحدة تأخذ كام؟', '6', 6, 'اقسم 36 على 6', '36 ÷ 6 = 6 حلاوات لكل واحدة', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
