(38, 4, 'mcq', 'ar', 'سارة بتقرب عدد سكان مدينتها', 'عدد سكان المدينة 47٬329. قربي الرقم لأقرب ألف؟', NULL, NULL, 'شوف الرقم اللي في خانة المئات، لو أقل من 5 نزّل', 'الرقم في خانة المئات = 3 (أقل من 5)، فنقرب لـ 47٬000', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
