(49, 5, 'mcq', 'ar', 'أحمد بيرتب الكور في صفوف متساوية', 'أحمد عنده 14 كورة. هل يقدر يرتبهم في صفين متساويين؟', NULL, NULL, 'لو الرقم زوجي يكون يتقسم على 2', '14 عدد زوجي لأنه بيتقسم على 2 بدون باقي (14 ÷ 2 = 7)، فأيوا يقدر', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
