(52, 5, 'mcq', 'ar', 'نور بتلعب لعبة زوجي/فردي مع أختها', 'لو جمعنا عدد فردي + عدد فردي، النتيجة بتكون إيه؟', NULL, NULL, 'جرب مثال: 3 + 5 = ؟', 'فردي + فردي = زوجي دايماً. مثال: 3 + 5 = 8 (زوجي)', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
