(55, 5, 'mcq', 'ar', 'ياسمين توزع تفاح على أطباق بالتساوي', 'ياسمين عندها 15 تفاحة. أي عدد أطباق تقدر توزع عليه بالتساوي من غير باقي؟', NULL, NULL, 'دوري على عوامل 15', 'عوامل 15 هي 1، 3، 5، 15. فتقدر توزع على 3 أو 5 أطباق بالتساوي', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(56, 5, 'mcq', 'ar', 'خالد بيصنف الأعداد في حصة الرياضيات', 'أي عدد من دول عدد فردي؟', NULL, NULL, 'العدد الفردي مش بيتقسم على 2 بالتساوي', '37 عدد فردي لأن 37 ÷ 2 = 18 والباقي 1', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(57, 5, 'open_ended', 'ar', 'سارة بتحل سؤال عن المضاعفات', 'إيه ناتج 8 × 7؟ (وهو مضاعف مشترك لـ 8 و 7)', '56', 56, 'اضرب 8 في 7', '8 × 7 = 56', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(58, 5, 'open_ended', 'ar', 'نور بتعد عوامل رقم', 'العدد 18 له كم عامل؟ (العوامل: 1، 2، 3، 6، 9، 18)', '6', 6, 'عد الأرقام اللي تقسم 18 من غير باقي', 'عوامل 18: 1، 2، 3، 6، 9، 18 = 6 عوامل', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(59, 5, 'open_ended', 'ar', 'كريم بيحسب مضاعفات في لعبة حسابية', 'إيه خامس مضاعف للعدد 4؟', '20', 20, 'اضرب 4 × 5', 'مضاعفات 4: 4، 8، 12، 16، 20. الخامس = 20', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(60, 5, 'open_ended', 'ar', 'أحمد بيرتب كراسي في صفوف', 'أحمد عنده 48 كرسي. لو رتبهم في صفوف كل صف 8 كراسي، هيطلع كم صف؟', '6', 6, 'اقسم 48 على 8', '48 ÷ 8 = 6 صفوف', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
