(62, 6, 'mcq', 'ar', 'سارة قسمت الكيكة 4 حتت متساوية', 'سارة أكلت حتة واحدة من 4. أي كسر يمثل اللي أكلته؟', NULL, NULL, 'عدد الحتت اللي أكلتها فوق وعدد الحتت الكلي تحت', 'أكلت حتة من 4 = 1/4', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(63, 6, 'mcq', 'ar', 'كريم عنده لوح فواكه متقسم 10 مربعات', 'أي كسر أكبر: 3/10 ولا 7/10؟', NULL, NULL, 'لو المقام واحد، قارن البسط', 'المقام واحد (10)، و 7 > 3، فـ 7/10 أكبر', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(64, 6, 'mcq', 'ar', 'نور أكلت جزء من البيتزا المقسمة 6 حتت', 'نور أكلت 2/6 من البيتزا. الكسر هذا يساوي كم في أبسط صورة؟', NULL, NULL, 'دوري على رقم يقسم البسط والمقام', '2/6 = 1/3 (قسمنا البسط والمقام على 2)', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(65, 6, 'mcq', 'ar', 'عمر بيتعلم الكسور المتكافئة في حصة الرياضيات', 'أي كسر يكافئ 1/2؟', NULL, NULL, 'اضرب البسط والمقام في نفس الرقم', '1/2 = 2/4 = 3/6 = 4/8 (نضرب البسط والمقام في نفس العدد)', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(66, 6, 'mcq', 'ar', 'ياسمين تقسم لوح فواكه على أصدقائها', 'لوح الفواكه متقسم 12 مربع. ياسمين أكلت 4 مربعات. أكلت قد إيه؟', NULL, NULL, 'اكتبي الكسر وبسطيه', '4/12 = 1/3 (قسمنا على 4)', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(67, 6, 'mcq', 'ar', 'مريم بتقارن حصص الكيك بين أخواتها', 'أي أكبر: 1/2 ولا 1/4؟', NULL, NULL, 'لو البسط واحد، المقام الأصغر يكون الكسر الأكبر', 'نفس البسط (1)، والمقام 2 < 4، فـ 1/2 أكبر من 1/4', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(68, 6, 'mcq', 'ar', 'خالد اشترى بيتزا كبيرة متقسمة 8 حتت', 'خالد أكل 2/8 وأخوه أكل 2/8. المتبقي قد إيه؟', NULL, NULL, 'اجمع اللي اتاكل واطرح من 8/8', '2/8 + 2/8 = 4/8. الالمتبقي = 8/8 - 4/8 = 4/8 = 1/2', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(69, 6, 'open_ended', 'ar', 'أحمد أكل جزء من بيتزا مقسمة 6 حتت', 'أحمد أكل 2 حتة من 6. البسط في الكسر هذا كام؟', '2', 2, 'البسط هو عدد الحتت اللي أكلها', 'أكل 2 من 6، فالكسر = 2/6 والبسط = 2', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(70, 6, 'open_ended', 'ar', 'سارة بتبسط كسور في الواجب', 'بسطي الكسر 4/8. المقام في أبسط صورة كام؟', '2', 2, 'اقسمي البسط والمقام على 4', '4/8 = 1/2 (قسمنا على 4). المقام = 2', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(71, 6, 'open_ended', 'ar', 'كريم قسم كيكة 5 حتت ومحدش أكل حاجة', 'لو الكيكة كلها متقسمة 5 حتت، الكيكة كاملة بتتكتب كسر إزاي؟ البسط كام؟', '5', 5, 'الكل يعني البسط = المقام', 'الكيكة الكاملة = 5/5، فالبسط = 5', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(72, 6, 'open_ended', 'ar', 'نور بتقارن كسور في حصة الرياضيات', 'لوح فواكه متقسم 10 مربعات. نور أكلت 5 مربعات. أكلت كم على 10 من اللوح؟ (اكتب البسط)', '5', 5, 'البسط = عدد المربعات اللي اتاكلت', 'أكلت 5 من 10 = 5/10 = 1/2. البسط = 5', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(73, 7, 'mcq', 'ar', 'ماما بتشتري فاكهة من البقال', 'ماما اشترت 3 كيلو تفاح و 2 كيلو برتقال. اشترت كم كيلو فاكهة في المجموع؟', NULL, NULL, 'اجمع الكيلوهات مع بعض', '3 + 2 = 5 كيلو فاكهة', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(74, 7, 'mcq', 'ar', 'كريم بيقيس طول الفصل', 'طول الفصل 8 متر وعرضه 6 متر. المحيط كم متر؟', NULL, NULL, 'محيط المستطيل = 2 × (الطول + العرض)', 'المحيط = 2 × (8 + 6) = 2 × 14 = 28 متر', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(75, 7, 'mcq', 'ar', 'سارة بتملى زجاجات مياه للرحلة', 'سارة عندها جركن 5 لتر مياه وملت 3 زجاجات كل واحدة نص لتر. كم يتبقى لتر؟', NULL, NULL, 'احسبي المياه اللي في الزجاجات واطرحيها', '3 زجاجات × 0.5 لتر = 1.5 لتر. الالمتبقي = 5 - 1.5 = 3.5 لتر', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(76, 7, 'mcq', 'ar', 'أحمد بيوزن شنطة المدرسة', 'شنطة أحمد وزنها 4 كيلو. لو حط فيها كتاب وزنه 500 جرام، الوزن الكلي كام؟', NULL, NULL, '500 جرام = نص كيلو', '500 جرام = 0.5 كيلو. الوزن = 4 + 0.5 = 4.5 كيلو = 4 كيلو ونص', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(77, 7, 'mcq', 'ar', 'نور بتقيس قماش حتى تعمل فستان', 'نور محتاجة 2 متر قماش. لو القماش عندها 150 سم، ينفع ولا لأ؟', NULL, NULL, 'حولي المتر لسنتيمتر: 1 متر = 100 سم', '2 متر = 200 سم. عندها 150 سم بس، فمش كفاية ومحتاجة 50 سم إضافية', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(78, 7, 'mcq', 'ar', 'ياسمين بتحسب كمية اللبن اللي محتاجاها لوصفة', 'الوصفة محتاجة لتر ونص لبن. كم مل ده؟', NULL, NULL, '1 لتر = 1000 مل', '1 لتر = 1000 مل. لتر ونص = 1000 + 500 = 1500 مل', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(79, 7, 'mcq', 'ar', 'عمر بيشتري رز من البقالة', 'ماما طلبت 2 كيلو رز. كم جرام ده؟', NULL, NULL, '1 كيلو = 1000 جرام', '2 كيلو = 2 × 1000 = 2000 جرام', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(80, 7, 'mcq', 'ar', 'مريم بتقيس طولها وطول أختها', 'طول مريم 140 سم وطول أختها 1 متر و 25 سم. الفرق كم سم؟', NULL, NULL, 'حولي طول الأخت لسنتيمتر الأول', '1 متر و 25 سم = 125 سم. الفرق = 140 - 125 = 15 سم', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(81, 7, 'open_ended', 'ar', 'خالد بيشتري بطيخة من الخضري', 'البطيخة وزنها 3 كيلو. كم جرام ده؟', '3000', 3000, '1 كيلو = 1000 جرام', '3 كيلو = 3 × 1000 = 3000 جرام', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(82, 7, 'open_ended', 'ar', 'سارة بتحسب طول سور الحديقة', 'حديقة مربعة طول ضلعها 5 متر. المحيط كم متر؟', '20', 20, 'محيط المربع = 4 × طول الضلع', 'محيط المربع = 4 × 5 = 20 متر', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(83, 7, 'open_ended', 'ar', 'أحمد بيملى حوض السمك بالمياه', 'حوض السمك محتاج 4 لتر مياه. كم مل ده؟', '4000', 4000, '1 لتر = 1000 مل', '4 لتر = 4 × 1000 = 4000 مل', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(84, 7, 'open_ended', 'ar', 'نور بتقيس طول حبل النط', 'حبل النط طوله 2 متر و 50 سم. كم سم في المجموع؟', '250', 250, 'حولي المتر لسنتيمتر واجمعي', '2 متر = 200 سم. 200 + 50 = 250 سم', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(85, 8, 'mcq', 'ar', 'أحمد وصاحبه بياكلوا بيتزا متقسمة 8 حتت', 'أحمد أكل 3/8 من البيتزا وصاحبه أكل 2/8. أكلوا كم مع بعض؟', NULL, NULL, 'اجمع البسط مع بعض والمقام يتبقى زي ما هو', '3/8 + 2/8 = 5/8 لأن المقام واحد فبنجمع البسط بس', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(86, 8, 'mcq', 'ar', 'سارة عندها كيكة مقسومة 6 حتت', 'سارة أكلت 4/6 من الكيكة وأختها أكلت 1/6. المتبقي كم من الكيكة؟', NULL, NULL, 'اجمع اللي اتاكل الأول وبعدين اطرح من الواحد الصحيح', '4/6 + 1/6 = 5/6 اتاكلوا، فالالمتبقي = 6/6 - 5/6 = 1/6', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(87, 8, 'mcq', 'ar', 'ماما اشترت لتر عصير وقسمته على 5 كوبايات متساوية', 'لو شربت 3/5 من العصير، تحتاج أن تشرب كم أيضاً حتى تخلّص الكل؟', NULL, NULL, 'الكل = 5/5، اطرح منه اللي شربته', '5/5 - 3/5 = 2/5 هو اللي المتبقي', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(88, 8, 'mcq', 'ar', 'في حصة الرسم، مريم لونت جزء من اللوحة بالأزرق وجزء بالأحمر', 'مريم لونت 2/10 أزرق و 5/10 أحمر. لونت كم من اللوحة كلها؟', NULL, NULL, 'المقام واحد فاجمع البسط', '2/10 + 5/10 = 7/10 من اللوحة اتلونت', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(89, 8, 'mcq', 'ar', 'طارق بيعمل واجب الرياضيات وخلّص جزء من التمارين', 'طارق حل 3/4 من التمارين الصبح و 1/4 بالليل. حل كم من التمارين؟', NULL, NULL, 'اجمع الكسرين واللي المقام فيهم واحد', '3/4 + 1/4 = 4/4 = 1 يعني حل كل التمارين', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(90, 8, 'mcq', 'ar', 'نور تقسم شريط ملون 8 أجزاء متساوية حتى تعمل أساور', 'نور استخدمت 5/8 من الشريط. لو قصت أيضاً 1/8، يتبقى قد إيه؟', NULL, NULL, 'اجمع اللي استخدمته وبعدين اطرح من 8/8', '5/8 + 1/8 = 6/8 استُخدمت، فالباقي = 8/8 - 6/8 = 2/8', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(91, 8, 'mcq', 'ar', 'عمر بيلعب لعبة وكسب نقط على مراحل', 'في المرحلة الأولى كسب 4/10 وفي التانية كسب 3/10. المجموع كام؟', NULL, NULL, 'المقام واحد = 10، اجمع البسط', '4/10 + 3/10 = 7/10', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(92, 8, 'mcq', 'ar', 'كريم وخالد بياكلوا تورتة عيد ميلاد متقسمة 3 حتت كبار', 'كريم أكل 1/3 وخالد أكل 1/3. الالمتبقي قد إيه؟', NULL, NULL, 'اجمع اللي اتاكل واطرح من الكل', '1/3 + 1/3 = 2/3 اتاكلوا، فالالمتبقي = 3/3 - 2/3 = 1/3', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(93, 8, 'open_ended', 'ar', 'ياسمين تأكل فواكه مقسومة 5 مربعات', 'ياسمين أكلت 2/5 وأختها أكلت 1/5. كم يتبقى على 5 من الفواكه؟', '2', 2, 'اجمع اللي اتاكل واطرح من 5/5', '2/5 + 1/5 = 3/5 اتاكلوا. الالمتبقي = 5/5 - 3/5 = 2/5. البسط = 2', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(94, 8, 'open_ended', 'ar', 'في المدرسة بيوزعوا ساندوتشات مقسومة 4 أجزاء', 'لو أكلت 3/4 من الساندوتش، اطرح من الكل. البسط بتاع الكم يتبقى؟', '1', 1, '4/4 - 3/4 = ؟/4', '4/4 - 3/4 = 1/4، فالبسط = 1', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(95, 8, 'open_ended', 'ar', 'حازم ملا خزان مية البيت على مرتين', 'المرة الأولى ملا 3/8 والتانية ملا 4/8. اجمع الكسرين. البسط كام؟', '7', 7, '3 + 4 = ؟ والمقام يتبقى 8', '3/8 + 4/8 = 7/8، فالبسط = 7', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(96, 8, 'open_ended', 'ar', 'في الفسحة، الأولاد أكلوا جزء من البطيخة والبنات أكلوا جزء تاني', 'الأولاد أكلوا 4/6 والبنات 1/6. مجموع اللي اتاكل: البسط كام؟', '5', 5, '4 + 1 = ؟', '4/6 + 1/6 = 5/6، فالبسط = 5', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(97, 9, 'mcq', 'ar', 'أحمد رايح السوبر ماركت يشتري حاجات للبيت', 'سعر اللبن 7٫50 جنيه وسعر العصير 7٫25 جنيه. أي أغلى؟', NULL, NULL, 'قارن الجزء العشري: 50 ولا 25 أكبر؟', '7٫50 أكبر من 7٫25 لأن 50 في الجزء العشري أكبر من 25', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(98, 9, 'mcq', 'ar', 'في حصة العلوم بيقيسوا أطوال النباتات', 'نبتة أحمد طولها 12٫3 سم ونبتة سارة طولها 12٫7 سم. مين نبتتها أطول؟', NULL, NULL, 'الجزء الصحيح واحد، قارن العشري', '12٫7 > 12٫3 لأن 7 أعشار أكبر من 3 أعشار', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(99, 9, 'mcq', 'ar', 'ماما بتشتري فاكهة من البقال', 'الرقم 3٫45 جنيه: الـ 4 قيمتها المكانية إيه؟', NULL, NULL, 'الـ 4 في خانة الأعشار', 'الـ 4 في خانة الأعشار يعني قيمتها 4 أعشار = 0٫4', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(100, 9, 'mcq', 'ar', 'الأولاد بيتسابقوا في الجري في حصة الألعاب', 'رتّب الأزمنة دي من الأسرع للأبطأ: 12٫9 ثانية، 12٫3 ثانية، 12٫5 ثانية', NULL, NULL, 'الأسرع هو اللي وقته أقل', '12٫3 < 12٫5 < 12٫9 فالترتيب من الأسرع: 12٫3 ثم 12٫5 ثم 12٫9', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000');
INSERT INTO `questions` (`id`, `topic_id`, `question_type`, `locale`, `real_life_context`, `question_text`, `correct_answer`, `correct_answer_numeric`, `hint_text`, `explanation`, `image_url`, `created_at`, `updated_at`) VALUES
(101, 9, 'mcq', 'ar', 'في المكتبة بيشتروا أدوات مدرسية', 'القلم بـ 3٫75 جنيه والكراسة بـ 5٫20 جنيه. أي أغلى وبكم فرق؟', NULL, NULL, 'قارن الأعداد العشرية: مين أكبر؟', '5٫20 > 3٫75 فالكراسة أغلى. الفرق = 5٫20 - 3٫75 = 1٫45 جنيه', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(102, 9, 'mcq', 'ar', 'بابا بيملى بنزين العربية', 'سعر لتر البنزين 12٫50 جنيه. الرقم 5 في خانة إيه؟', NULL, NULL, 'الـ 5 بعد العلامة العشرية في أول خانة', 'الـ 5 في خانة الأعشار يعني قيمتها 5 أعشار = 0٫50', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(103, 9, 'mcq', 'ar', 'في السوبر ماركت يشاهدون أسعار التفاح', 'أي عدد أكبر: 4٫08 ولا 4٫80؟', NULL, NULL, 'قارن خانة الأعشار: 0 ولا 8؟', '4٫80 أكبر لأن خانة الأعشار فيها 8 بينما التاني 0', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(104, 9, 'mcq', 'ar', 'المدرس بيسأل عن الكسور العشرية', 'العدد 0٫7 يساوي كم من عشرة؟', NULL, NULL, 'العشري الأول بعد النقطة هو عدد الأعشار', '0٫7 = 7 من 10 = 7/10', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(105, 9, 'open_ended', 'ar', 'في الصيدلية ماما بتشتري دوا', 'سعر الدوا 15٫75 جنيه. الرقم 7 قيمته المكانية كام؟ اكتب الإجابة كعدد عشري.', '0٫7', 0.7, 'الـ 7 في خانة الأعشار', 'الـ 7 في خانة الأعشار قيمتها 0٫7', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(106, 9, 'open_ended', 'ar', 'خالد بيوزن شنطة المدرسة', 'وزن الشنطة 3٫4 كجم ووزن اللانش بوكس 1٫2 كجم. مين أتقل بكم كجم؟', '2٫2', 2.2, 'اطرح الأصغر من الأكبر', '3٫4 - 1٫2 = 2٫2 كجم فرق', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(107, 9, 'open_ended', 'ar', 'في محل الفواكه، سعر الكيلو مكتوب بالعشري', 'رتّب من الأصغر للأكبر: 2٫9 ، 2٫3 ، 2٫7. العدد اللي في النص (التاني) كام؟', '2٫7', 2.7, 'الترتيب: 2٫3 ثم ؟ ثم 2٫9', 'الترتيب: 2٫3 ، 2٫7 ، 2٫9. العدد في النص = 2٫7', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(108, 9, 'open_ended', 'ar', 'ياسمين بتحسب مصروفها اليومي', 'عند ياسمين 8٫50 جنيه. اشترت ساندوتش بـ 5٫25 جنيه. المتبقي معاها كام؟', '3٫25', 3.25, 'اطرح سعر الساندوتش من المبلغ', '8٫50 - 5٫25 = 3٫25 جنيه', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(109, 10, 'mcq', 'ar', 'أحمد بيشتري أكل من الكانتين', 'ساندوتش بـ 8٫50 جنيه وعصير بـ 4٫75 جنيه. المجموع كام؟', NULL, NULL, 'حط العلامة العشرية تحت بعض واجمع', '8٫50 + 4٫75 = 13٫25 جنيه', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(110, 10, 'mcq', 'ar', 'سارة معاها مال وراحت المكتبة تشتري كتاب', 'سارة معاها 20٫00 جنيه واشترت كتاب بـ 14٫50 جنيه. الباقي كام؟', NULL, NULL, 'اطرح سعر الكتاب من المال', '20٫00 - 14٫50 = 5٫50 جنيه', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(111, 10, 'mcq', 'ar', 'بابا بيحسب فاتورة البقالة', 'جبنة بـ 12٫30 جنيه وزبدة بـ 9٫85 جنيه. المجموع كام؟', NULL, NULL, 'اجمع الأجزاء العشرية مع بعض والصحيحة مع بعض', '12٫30 + 9٫85 = 22٫15 جنيه', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(112, 10, 'mcq', 'ar', 'خالد بيشتري هدية لصاحبه', 'عنده 50٫00 جنيه واشترى لعبة بـ 35٫75 جنيه. الباقي كام؟', NULL, NULL, 'اطرح: 50٫00 - 35٫75', '50٫00 - 35٫75 = 14٫25 جنيه', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(113, 10, 'mcq', 'ar', 'ماما اشترت خضار من السوق', 'طماطم بـ 6٫25 جنيه وخيار بـ 3٫50 جنيه وبصل بـ 2٫75 جنيه. المجموع كام؟', NULL, NULL, 'اجمع الأتنين الأولانيين وبعدين أضف التالت', '6٫25 + 3٫50 = 9٫75 ، ثم 9٫75 + 2٫75 = 12٫50 جنيه', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(114, 10, 'mcq', 'ar', 'نور بتحسب وزنها قبل وبعد الرجيم', 'وزن نور كان 45٫8 كجم وبقى 43٫5 كجم. نقصت كم كجم؟', NULL, NULL, 'اطرح الوزن الجديد من القديم', '45٫8 - 43٫5 = 2٫3 كجم', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(115, 10, 'mcq', 'ar', 'الأولاد بيتسابقوا في القفز الطويل', 'أحمد قفز 3٫25 متر وعمر قفز 2٫90 متر. الفرق كم متر؟', NULL, NULL, 'اطرح المسافة الأقل من الأكبر', '3٫25 - 2٫90 = 0٫35 متر', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(116, 10, 'mcq', 'ar', 'ياسمين بتجمع مال في الحصالة', 'كان فيها 25٫40 جنيه وأضافت 12٫60 جنيه. المجموع كام؟', NULL, NULL, 'اجمع الأعداد العشرية', '25٫40 + 12٫60 = 38٫00 جنيه', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(117, 10, 'open_ended', 'ar', 'مريم بتشتري أدوات رسم', 'ألوان بـ 15٫30 جنيه وفرشاة بـ 7٫50 جنيه. المجموع كم جنيه؟', '22٫80', 22.8, 'اجمع الجزء العشري مع بعض والصحيح مع بعض', '15٫30 + 7٫50 = 22٫80 جنيه', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(118, 10, 'open_ended', 'ar', 'عمر بيشتري من كافيتيريا المدرسة', 'معاه 10٫00 جنيه واشترى عصير بـ 3٫25 جنيه وموز بـ 2٫50 جنيه. الباقي كام؟', '4٫25', 4.25, 'اجمع المشتريات الأول وبعدين اطرح من 10', '3٫25 + 2٫50 = 5٫75، ثم 10٫00 - 5٫75 = 4٫25 جنيه', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(119, 10, 'open_ended', 'ar', 'طارق بيحسب طوله السنة دي والسنة اللي فاتت', 'طوله السنة دي 142٫5 سم والسنة اللي فاتت كان 138٫8 سم. طال كم سم؟', '3٫7', 3.7, 'اطرح الطول القديم من الجديد', '142٫5 - 138٫8 = 3٫7 سم', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(120, 10, 'open_ended', 'ar', 'ماما بتحسب فاتورة الموبايل', 'فاتورة هذا الشهر 85٫40 جنيه والشهر اللي فات 79٫60 جنيه. مجموع الشهرين كام؟', '165', 165, 'اجمع الفاتورتين', '85٫40 + 79٫60 = 165٫00 جنيه', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(121, 11, 'mcq', 'ar', 'أحمد يذهب المدرسة كل يوم الصبح', 'أحمد ساب البيت الساعة 7:15 ووصل المدرسة 7:45. الطريق أخد قد إيه؟', NULL, NULL, 'احسب الفرق بين الوقتين', '7:45 - 7:15 = 30 دقيقة', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(122, 11, 'mcq', 'ar', 'سارة عندها حصة موسيقى في المدرسة', 'الحصة بتبدأ الساعة 10:30 ومدتها 45 دقيقة. بتخلص الساعة كام؟', NULL, NULL, 'أضف 45 دقيقة على 10:30', '10:30 + 45 دقيقة = 11:15', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(123, 11, 'mcq', 'ar', 'العيلة بتتفرج على ماتش كورة على التلفزيون', 'الماتش بدأ الساعة 9:00 بالليل وخلص 10:45. مدة الماتش قد إيه؟', NULL, NULL, 'من 9:00 لـ 10:00 = ساعة، و45 دقيقة', 'من 9:00 لـ 10:45 = ساعة و 45 دقيقة = 105 دقيقة', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(124, 11, 'mcq', 'ar', 'خالد بيركب مترو القاهرة من المرج لجامعة القاهرة', 'خالد ركب المترو الساعة 8:20 والرحلة أخدت 55 دقيقة. وصل الساعة كام؟', NULL, NULL, '8:20 + 40 دقيقة = 9:00، وباقي 15 دقيقة', '8:20 + 55 دقيقة = 9:15', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(125, 11, 'mcq', 'ar', 'نور بتأخذ درس خصوصي بعد المدرسة', 'الدرس بيبدأ الساعة 4:00 ومدته ساعة ونص. بيخلص الساعة كام؟', NULL, NULL, 'ساعة ونص = 90 دقيقة', '4:00 + 1:30 = 5:30', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(126, 11, 'mcq', 'ar', 'الجدول المدرسي فيه 6 حصص في اليوم', 'اليوم الدراسي بيبدأ 7:30 الصبح وبيخلص 1:30 الضهر. مدته كم ساعة؟', NULL, NULL, 'احسب من 7:30 لـ 1:30', 'من 7:30 لـ 1:30 = 6 ساعات', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(127, 11, 'mcq', 'ar', 'بابا بيسافر بالقطر من القاهرة لإسكندرية', 'الساعة 14:00 بنظام 24 ساعة يعني كم بنظام 12 ساعة؟', NULL, NULL, 'اطرح 12 من الساعة لو أكبر من 12', '14:00 - 12 = 2:00 بعد الظهر', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(128, 11, 'mcq', 'ar', 'مريم بتطبخ مع ماما وتريد تعرف الأكل يخلص امتى', 'حطوا الأكل في الفرن الساعة 5:40 ومحتاج ساعة و 20 دقيقة. يطلع الساعة كام؟', NULL, NULL, '5:40 + 1 ساعة = 6:40، و20 دقيقة', '5:40 + 1:20 = 7:00', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(129, 11, 'open_ended', 'ar', 'عمر يذهب تمرين كورة القدم', 'التمرين بيبدأ 3:30 وبيخلص 5:15. مدة التمرين كم دقيقة؟', '105', 105, 'من 3:30 لـ 5:15 احسب الساعات والدقايق', 'من 3:30 لـ 5:15 = ساعة و 45 دقيقة = 105 دقيقة', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(130, 11, 'open_ended', 'ar', 'ياسمين بتشوف جدول مواعيد القطرات', 'القطر بيمشي الساعة 16:45 بنظام 24 ساعة. هذا يكون كم بنظام 12 ساعة؟ اكتب الساعة بس.', '4:45', 4.45, 'اطرح 12 من 16', '16 - 12 = 4، يكون الساعة 4:45 مساءً', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(131, 11, 'open_ended', 'ar', 'كريم بيذاكر للامتحان', 'بدأ المذاكرة 4:00 العصر وخلّص 6:30. ذاكر كم دقيقة؟', '150', 150, 'من 4:00 لـ 6:30 = ساعتين ونص', 'ساعتين ونص = 150 دقيقة', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(132, 11, 'open_ended', 'ar', 'حازم بيركب أتوبيس المدرسة', 'الأتوبيس يمر عليه 6:50 الصبح والمدرسة بتبدأ 7:30. بيوصل قبل المدرسة بكم دقيقة لو الطريق 25 دقيقة؟', '15', 15, '6:50 + 25 = وقت الوصول، وبعدين احسب الفرق لـ 7:30', '6:50 + 25 = 7:15. الفرق بين 7:15 و 7:30 = 15 دقيقة', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(133, 12, 'mcq', 'ar', 'أحمد يريد يحوّط أوضته بشريط زينة', 'أوضة أحمد طولها 4 متر وعرضها 3 متر. محيط الأوضة كم متر؟', NULL, NULL, 'محيط المستطيل = 2 × (الطول + العرض)', 'المحيط = 2 × (4 + 3) = 2 × 7 = 14 متر', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(134, 12, 'mcq', 'ar', 'سارة تريد تفرش أوضتها بسجادة', 'أوضة سارة طولها 5 متر وعرضها 4 متر. مساحة الأوضة كم متر مربع؟', NULL, NULL, 'مساحة المستطيل = الطول × العرض', 'المساحة = 5 × 4 = 20 متر مربع', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(135, 12, 'mcq', 'ar', 'خالد بيحسب حجم ملعب الكورة في النادي', 'ملعب صغير طوله 20 متر وعرضه 10 متر. مساحته كم متر مربع؟', NULL, NULL, 'المساحة = الطول × العرض', 'المساحة = 20 × 10 = 200 متر مربع', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(136, 12, 'mcq', 'ar', 'نور تريد تعمل إطار لصورة مربعة', 'صورة مربعة طول ضلعها 6 متر. محيطها كم متر؟', NULL, NULL, 'محيط المربع = 4 × طول الضلع', 'المحيط = 4 × 6 = 24 متر', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(137, 12, 'mcq', 'ar', 'بابا بيبلّط حوش البيت', 'الحوش مربع طول ضلعه 8 متر. مساحته كم متر مربع؟', NULL, NULL, 'مساحة المربع = الضلع × الضلع', 'المساحة = 8 × 8 = 64 متر مربع', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(138, 12, 'mcq', 'ar', 'المدرسة تريد تعمل سور حوالين حديقة المدرسة', 'الحديقة مستطيلة طولها 15 متر وعرضها 10 متر. محتاجين كم متر سور؟', NULL, NULL, 'السور = المحيط = 2 × (الطول + العرض)', 'المحيط = 2 × (15 + 10) = 2 × 25 = 50 متر', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(139, 12, 'mcq', 'ar', 'مريم تريد تدهن حيطة أوضتها', 'الحيطة طولها 5 متر وارتفاعها 3 متر. مساحة الحيطة كم متر مربع؟', NULL, NULL, 'الحيطة مستطيل: المساحة = الطول × الارتفاع', 'المساحة = 5 × 3 = 15 متر مربع', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(140, 12, 'mcq', 'ar', 'عمر بيقارن بين مساحة أوضته وأوضة أخوه', 'أوضة عمر 4×3 متر وأوضة أخوه 3×3 متر. الفرق في المساحة كام؟', NULL, NULL, 'احسب مساحة كل أوضة واطرح', 'مساحة أوضة عمر = 12، أوضة أخوه = 9. الفرق = 12 - 9 = 3 متر مربع', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(141, 12, 'open_ended', 'ar', 'طارق بيحسب مساحة الصالة في البيت', 'الصالة مستطيلة طولها 6 متر وعرضها 4 متر. مساحتها كم متر مربع؟', '24', 24, 'المساحة = الطول × العرض', 'المساحة = 6 × 4 = 24 متر مربع', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(142, 12, 'open_ended', 'ar', 'ياسمين تريد تعمل برواز حوالين لوحة مربعة', 'اللوحة مربعة طول ضلعها 7 متر. محيطها كم متر؟', '28', 28, 'محيط المربع = 4 × الضلع', 'المحيط = 4 × 7 = 28 متر', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(143, 12, 'open_ended', 'ar', 'كريم بيعمل ملعب صغير في الحديقة', 'الملعب مستطيل طوله 12 متر وعرضه 8 متر. محيطه كم متر؟', '40', 40, 'المحيط = 2 × (الطول + العرض)', 'المحيط = 2 × (12 + 8) = 2 × 20 = 40 متر', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(144, 12, 'open_ended', 'ar', 'حازم بيحسب مساحة سطح البيت المربع', 'السطح مربع طول ضلعه 9 متر. مساحته كم متر مربع؟', '81', 81, 'مساحة المربع = الضلع × الضلع', 'المساحة = 9 × 9 = 81 متر مربع', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(145, 13, 'mcq', 'ar', 'ماما بتقدر فاتورة السوبر ماركت قبل ما تدفع', 'اشترت حاجات بـ 47 جنيه و 32 جنيه و 18 جنيه. قرّب كل عدد لأقرب عشرة واجمع.', NULL, NULL, '47 ≈ 50، 32 ≈ 30، 18 ≈ 20', '50 + 30 + 20 = 100 جنيه تقريبًا', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(146, 13, 'mcq', 'ar', 'بابا بيقدر تكلفة رحلة العيلة', 'قرّب العدد 374 لأقرب مية.', NULL, NULL, 'شوف رقم العشرات: 7 أكبر من 5 ولا أصغر؟', '374: رقم العشرات 7 ≥ 5 فنقرب لفوق = 400', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(147, 13, 'mcq', 'ar', 'أحمد بيحسب درجاته في الامتحانات', 'درجاته: 78 و 83 و 91. قرّب كل عدد لأقرب عشرة واجمع التقدير.', NULL, NULL, '78 ≈ 80، 83 ≈ 80، 91 ≈ 90', '80 + 80 + 90 = 250 تقريبًا', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(148, 13, 'mcq', 'ar', 'سارة بتقدر عدد الطلاب في المدرسة', 'في المدرسة 845 طالب. قرّب لأقرب مية.', NULL, NULL, 'رقم العشرات 4 أقل من 5', '845: رقم العشرات 4 < 5 فنقرب لتحت = 800', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(149, 13, 'mcq', 'ar', 'خالد بيقدر فاتورة المطعم', 'الفاتورة فيها: ساندوتش 29 جنيه ومشروب 14 جنيه. قرّب لأقرب عشرة وقدّر المجموع.', NULL, NULL, '29 ≈ 30، 14 ≈ 10', '30 + 10 = 40 جنيه تقريبًا', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(150, 13, 'mcq', 'ar', 'نور بتقدر وزن شنطة السفر', 'قرّب العدد 16٫7 لأقرب عدد صحيح.', NULL, NULL, 'الجزء العشري 7 أكبر من 5', '16٫7: الجزء العشري 7 ≥ 5 فنقرب لفوق = 17', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000');
