(157, 14, 'mcq', 'ar', 'أحمد بيرتب كراسي الفصل في صفوف', 'الصف الأول فيه 2 كرسي، التاني 5، التالت 8. الصف الرابع فيه كم كرسي؟', NULL, NULL, 'شوف الفرق بين كل عدد واللي بعده', 'النمط: +3 كل مرة. 2، 5، 8، 11', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(158, 14, 'mcq', 'ar', 'سارة بتعمل عقد من الخرز الملون', 'النمط: 3، 6، 12، 24، ___. العدد اللي بعد كده كام؟', NULL, NULL, 'كل عدد بيتضرب في كام؟', 'النمط: ×2 كل مرة. 24 × 2 = 48', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(159, 14, 'mcq', 'ar', 'خالد بيلعب لعبة أرقام مع أصدقائه', 'التسلسل: 50، 45، 40، 35، ___. العدد التالي كام؟', NULL, NULL, 'كل مرة بينقص كام؟', 'النمط: -5 كل مرة. 35 - 5 = 30', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(160, 14, 'mcq', 'ar', 'نور توزع فواكه على صديقاتها كل يوم', 'أول يوم وزعت 1، تاني يوم 4، تالت يوم 9، رابع يوم 16. خامس يوم كام؟', NULL, NULL, 'الأعداد دي هي مربعات: 1²، 2²، 3²، 4²...', 'دي مربعات الأعداد: 1، 4، 9، 16، 25. الخامس = 5² = 25', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(161, 14, 'mcq', 'ar', 'مريم بترتب أكواب على رفوف المطبخ', 'الرف الأول 10 أكواب، التاني 7، التالت 4. الرابع كام؟', NULL, NULL, 'كل رف بينقص 3', 'النمط: -3 كل مرة. 4 - 3 = 1', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(162, 14, 'mcq', 'ar', 'عمر بيحل لغز أرقام في مجلة أطفال', 'التسلسل: 2، 6، 18، 54، ___. العدد التالي كام؟', NULL, NULL, 'كل عدد بيتضرب في 3', 'النمط: ×3 كل مرة. 54 × 3 = 162', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(163, 14, 'mcq', 'ar', 'ياسمين بتعمل نمط بالمكعبات الملونة', 'النمط: 4، 7، 10، 13، ___. العدد اللي بعد كده كام؟', NULL, NULL, 'كل مرة بيزيد 3', 'النمط: +3. 13 + 3 = 16', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(164, 14, 'mcq', 'ar', 'طارق بيلاحظ نمط في أرقام البيوت في الشارع', 'أرقام البيوت: 3، 8، 13، 18، ___. البيت اللي بعد كده رقمه كام؟', NULL, NULL, 'الفرق بين كل رقم واللي بعده ثابت', 'النمط: +5 كل مرة. 18 + 5 = 23', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(165, 14, 'open_ended', 'ar', 'كريم بيحل تمرين أنماط في كتاب الرياضيات', 'أكمل النمط: 100، 90، 80، 70، ___. العدد التالي كام؟', '60', 60, 'كل مرة بينقص 10', 'النمط: -10 كل مرة. 70 - 10 = 60', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(166, 14, 'open_ended', 'ar', 'حازم بيرتب كتب على أرفف المكتبة', 'الرف الأول 5 كتب، التاني 10، التالت 15. الرف الرابع كم كتاب؟', '20', 20, 'كل رف بيزيد 5 كتب', 'النمط: +5. 15 + 5 = 20 كتاب', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(167, 14, 'open_ended', 'ar', 'نور بتعد نجوم ذهبية بتأخذها كل أسبوع', 'أول أسبوع 2، تاني أسبوع 4، تالت أسبوع 8، رابع أسبوع 16. خامس أسبوع كام؟', '32', 32, 'كل أسبوع العدد بيتضاعف', 'النمط: ×2. 16 × 2 = 32', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(168, 14, 'open_ended', 'ar', 'مريم بتعمل سلسلة أرقام في دفتر الرياضيات', 'التسلسل: 1، 4، 7، 10، 13، ___. العدد السادس كام؟', '16', 16, 'الفرق بين كل عدد والتاني = 3', 'النمط: +3 كل مرة. 13 + 3 = 16', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(169, 15, 'mcq', 'ar', 'ماما بتعمل كيكة العيد ومحتاجة تخلط دقيق. حطت 1/3 كيلو دقيق أبيض و1/4 كيلو دقيق ذرة.', 'كم كيلو دقيق حطت في الكيكة كلها؟', NULL, NULL, 'وحّد المقامات الأول: المقام المشترك لـ 3 و 4 هو 12', '1/3 + 1/4 = 4/12 + 3/12 = 7/12 كيلو', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(170, 15, 'mcq', 'ar', 'في رمضان، أحمد شرب 2/5 لتر عصير قمر الدين وسارة شربت 1/3 لتر.', 'كم لتر عصير اتشرب كله؟', NULL, NULL, 'المقام المشترك لـ 5 و 3 هو 15', '2/5 + 1/3 = 6/15 + 5/15 = 11/15 لتر', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(171, 15, 'mcq', 'ar', 'عندك 3/4 متر قماش وقصيت منه 1/6 متر حتى تعمل شنطة صغيرة.', 'كم متر قماش المتبقي؟', NULL, NULL, 'المقام المشترك لـ 4 و 6 هو 12', '3/4 - 1/6 = 9/12 - 2/12 = 7/12 متر', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(172, 15, 'mcq', 'ar', 'ماما صنعت أرز بلبن لإفطار رمضان. حطت 5/6 كوباية سكر الأول وبعدين زادت 1/4 كوباية.', 'كم كوباية سكر حطت كلها؟', NULL, NULL, 'المقام المشترك لـ 6 و 4 هو 12', '5/6 + 1/4 = 10/12 + 3/12 = 13/12 = 1 و 1/12 كوباية', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(173, 15, 'mcq', 'ar', 'في حصة العلوم، أجريت تجربة ومليت 2/3 الكوباية ميّة وبعدين فضيت منها 3/8.', 'كم من الكوباية المتبقي فيها ميّة؟', NULL, NULL, 'المقام المشترك لـ 3 و 8 هو 24', '2/3 - 3/8 = 16/24 - 9/24 = 7/24', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(174, 15, 'mcq', 'ar', 'بابا اشترى 3/5 كيلو جبنة رومي و1/2 كيلو جبنة بيضا للفطار.', 'كم كيلو جبنة اشترى كلها؟', NULL, NULL, 'المقام المشترك لـ 5 و 2 هو 10', '3/5 + 1/2 = 6/10 + 5/10 = 11/10 = 1 و 1/10 كيلو', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(175, 15, 'mcq', 'ar', 'كان معاك 7/8 لتر عصير مانجو وإديت صاحبك 2/5 لتر.', 'كم لتر المتبقي معاك؟', NULL, NULL, 'المقام المشترك لـ 8 و 5 هو 40', '7/8 - 2/5 = 35/40 - 16/40 = 19/40 لتر', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(176, 15, 'mcq', 'ar', 'في تحضير الكنافة، حطيت 1/3 كوباية سمنة وبعدين 1/6 كوباية زبدة.', 'كم كوباية دهون حطيت كلها؟', NULL, NULL, 'المقام المشترك لـ 3 و 6 هو 6', '1/3 + 1/6 = 2/6 + 1/6 = 3/6 = 1/2 كوباية', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(177, 15, 'open_ended', 'ar', 'في حفلة عيد ميلاد، أكلت 2/5 من التورتة وأخوك أكل 1/4.', 'كم من التورتة اتاكل كله؟ (اكتب الإجابة ككسر)', '13/20', 0.65, 'المقام المشترك لـ 5 و 4 هو 20', '2/5 + 1/4 = 8/20 + 5/20 = 13/20', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(178, 15, 'open_ended', 'ar', 'ماما اشترت 3/4 كيلو فراولة واستعملت 2/5 كيلو في العصير.', 'كم كيلو فراولة المتبقي؟ (اكتب الإجابة ككسر)', '7/20', 0.35, 'المقام المشترك لـ 4 و 5 هو 20', '3/4 - 2/5 = 15/20 - 8/20 = 7/20 كيلو', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(179, 15, 'open_ended', 'ar', 'مشيت 3/8 كيلومتر للمدرسة وبعدين 1/6 كيلومتر للمكتبة.', 'كم كيلومتر مشيت كلهم؟ (اكتب الإجابة ككسر)', '13/24', 0.5417, 'المقام المشترك لـ 8 و 6 هو 24', '3/8 + 1/6 = 9/24 + 4/24 = 13/24 كيلومتر', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(180, 15, 'open_ended', 'ar', 'كان عندك 5/6 لتر لبن واستخدمت 3/10 لتر في عمل البان كيك.', 'كم لتر لبن المتبقي؟ (اكتب الإجابة ككسر)', '8/15', 0.5333, 'المقام المشترك لـ 6 و 10 هو 30', '5/6 - 3/10 = 25/30 - 9/30 = 16/30 = 8/15 لتر', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(181, 16, 'mcq', 'ar', 'ماما صنعت بسبوسة وتريد تأخذ 2/3 الوصفة. الوصفة الأصلية محتاجة 3/4 كوباية سكر.', 'كم كوباية سكر هتحتاج؟', NULL, NULL, 'اضرب البسط × البسط والمقام × المقام', '2/3 × 3/4 = 6/12 = 1/2 كوباية', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(182, 16, 'mcq', 'ar', 'أحمد بيقطع خشب في حصة الأشغال. عنده لوح طوله 4/5 متر ويحتاج أن يقطع 1/2 منه.', 'كم متر هيكون طول القطعة اللي قطعها؟', NULL, NULL, 'اضرب الكسرين في بعض', '4/5 × 1/2 = 4/10 = 2/5 متر', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(183, 16, 'mcq', 'ar', 'عندك 3/5 كيلو فواكه ويريد توزع 1/3 منها على أصدقاءك في المدرسة.', 'كم كيلو فواكه ستوزع؟', NULL, NULL, 'اضرب 3/5 في 1/3', '3/5 × 1/3 = 3/15 = 1/5 كيلو', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(184, 16, 'mcq', 'ar', 'في رمضان، ماما بتعمل 5 أطباق كنافة. كل طبق محتاج 2/3 كوباية سمنة.', 'كم كوباية سمنة هتحتاج كلها؟', NULL, NULL, 'اضرب العدد الصحيح في الكسر: 5 × 2/3', '5 × 2/3 = 10/3 = 3 و 1/3 كوباية', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(185, 16, 'mcq', 'ar', 'أرض الملعب طولها 3/4 كيلومتر وعرضها 2/5 كيلومتر.', 'كم مساحتها بالكيلومتر المربع؟', NULL, NULL, 'المساحة = الطول × العرض', '3/4 × 2/5 = 6/20 = 3/10 كيلومتر مربع', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(186, 16, 'mcq', 'ar', 'جدو عنده قطعة أرض ومداك 2/7 منها. وانت قررت تزرع 3/4 من نصيبك برسيم.', 'كم من الأرض كلها هتتزرع برسيم؟', NULL, NULL, 'اضرب نصيبك × الجزء اللي هتزرعه', '2/7 × 3/4 = 6/28 = 3/14', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(187, 16, 'mcq', 'ar', 'في المطبخ، الوصفة محتاجة 4/9 كوباية زيت. ماما تريد تعمل نص الوصفة بس.', 'كم كوباية زيت هتستخدم؟', NULL, NULL, 'اضرب 4/9 × 1/2', '4/9 × 1/2 = 4/18 = 2/9 كوباية', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(188, 16, 'mcq', 'ar', 'عندك 7/8 لتر عصير ليمون وتحتاج أن تأخذ 2/3 منه تحطه في الثلاجة.', 'كم لتر هتحط في الثلاجة؟', NULL, NULL, 'اضرب 7/8 × 2/3', '7/8 × 2/3 = 14/24 = 7/12 لتر', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(189, 16, 'open_ended', 'ar', 'ماما عندها 3/4 كيلو لحمة وتريد تستخدم 2/5 منها لشوربة الإفطار.', 'كم كيلو لحمة هتستخدم في الشوربة؟ (اكتب الإجابة ككسر)', '3/10', 0.3, 'اضرب الكسرين: 3/4 × 2/5', '3/4 × 2/5 = 6/20 = 3/10 كيلو', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(190, 16, 'open_ended', 'ar', 'بابا اشترى 4 أمتار قماش ويريد يستخدم 3/8 منهم لستارة الصالون.', 'كم متر قماش محتاج للستارة؟ (اكتب الإجابة ككسر)', '3/2', 1.5, 'اضرب 4 × 3/8', '4 × 3/8 = 12/8 = 3/2 = 1.5 متر', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(191, 16, 'open_ended', 'ar', 'حوش المدرسة مساحته 5/6 فدان. المدير قرر يعمل 2/5 منه ملعب.', 'كم فدان هيكون الملعب؟ (اكتب الإجابة ككسر)', '1/3', 0.3333, 'اضرب 5/6 × 2/5 وبسّط الناتج', '5/6 × 2/5 = 10/30 = 1/3 فدان', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(192, 16, 'open_ended', 'ar', 'في العيد، جدتي صنعت 6 صواني بسبوسة. كل صينية محتاجة 3/4 كوباية سكر.', 'كم كوباية سكر محتاجة كلها؟ (اكتب الإجابة ككسر)', '9/2', 4.5, 'اضرب 6 × 3/4', '6 × 3/4 = 18/4 = 9/2 = 4.5 كوباية', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(193, 17, 'mcq', 'ar', 'عندك 3/4 كيلو حلاوة طحينية ويريد تقسمها على 3 أأصدقاء بالتساوي.', 'كل واحد هيأخذ كم كيلو؟', NULL, NULL, 'القسمة على عدد صحيح = الضرب في مقلوبه: 3/4 ÷ 3 = 3/4 × 1/3', '3/4 ÷ 3 = 3/4 × 1/3 = 3/12 = 1/4 كيلو', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(194, 17, 'mcq', 'ar', 'ماما عندها 2/3 لتر عصير وتريد تملا أكواب كل واحد 1/6 لتر.', 'كم كوباية هتقدر تملا؟', NULL, NULL, 'اقسم الكمية الكلية ÷ حجم الكوباية: 2/3 ÷ 1/6', '2/3 ÷ 1/6 = 2/3 × 6/1 = 12/3 = 4 أكواب', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(195, 17, 'mcq', 'ar', 'عندك 4/5 كيلو فول سوداني ويريد تحط في كل كيس 2/5 كيلو.', 'كم كيس هتقدر تملا؟', NULL, NULL, 'اقسم 4/5 ÷ 2/5 = 4/5 × 5/2', '4/5 ÷ 2/5 = 4/5 × 5/2 = 20/10 = 2 كيس', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(196, 17, 'mcq', 'ar', 'حبل طوله 5/6 متر وتحتاج أن تقطعه قطع كل واحدة 1/3 متر.', 'كم قطعة هتطلع؟', NULL, NULL, 'اقسم 5/6 ÷ 1/3 = 5/6 × 3/1', '5/6 ÷ 1/3 = 5/6 × 3/1 = 15/6 = 5/2 = 2 و 1/2 قطعة', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(197, 17, 'mcq', 'ar', 'عندك 7/8 كيلو جبنة ويريد تقسمها على 7 ساندويتشات بالتساوي.', 'كل ساندويتش هيأخذ كم كيلو جبنة؟', NULL, NULL, 'اقسم 7/8 ÷ 7', '7/8 ÷ 7 = 7/8 × 1/7 = 7/56 = 1/8 كيلو', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(198, 17, 'mcq', 'ar', 'في درس الطبخ، عندك 3/4 كوباية عسل وكل حلوى محتاجة 3/8 كوباية.', 'كم حلوى تقدر تعمل؟', NULL, NULL, 'اقسم 3/4 ÷ 3/8', '3/4 ÷ 3/8 = 3/4 × 8/3 = 24/12 = 2 حلوى', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(199, 17, 'mcq', 'ar', 'خالتي عندها 2/3 متر شريطة ساتان وتريد تعمل فيونكات كل واحدة 1/9 متر.', 'كم فيونكة هتقدر تعمل؟', NULL, NULL, 'اقسم 2/3 ÷ 1/9', '2/3 ÷ 1/9 = 2/3 × 9/1 = 18/3 = 6 فيونكات', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000'),
(200, 17, 'mcq', 'ar', 'في المصنع، عندك 5/6 طن رمل وتحتاج أن تقسمه على شاحنات كل واحدة تشيل 5/12 طن.', 'كم شاحنة محتاج؟', NULL, NULL, 'اقسم 5/6 ÷ 5/12', '5/6 ÷ 5/12 = 5/6 × 12/5 = 60/30 = 2 شاحنة', NULL, '2026-04-06 00:00:00.000', '2026-04-06 00:00:00.000');
